const d = $json;
const env = Number(d.env_score ?? 50);
const title = Number(d.title_risk_score ?? 50);
const margin = Number(d.margin_pct ?? 0);
const location = Number(d.neighborhood_condition_score ?? 50);
const und = Boolean(d.und_flag);
const demolition = Boolean(d.demolition_flag);
const missingLegal = !d.legal_description || d.legal_description === 'unknown';
let decision = 'watchlist';
let finalScore = (100-env)*0.25 + (100-title)*0.35 + Math.min(Math.max(margin,0),100)*0.30 + location*0.10;
if (und || demolition || missingLegal) { decision = 'reject'; finalScore = Math.min(finalScore, 20); }
else if (finalScore >= 75) decision = 'approved';
else if (finalScore < 50) decision = 'reject';
const summary = `Decision=${decision}; score=${finalScore.toFixed(1)}; veto=${und||demolition||missingLegal}`;
return [{json:{...d, final_score:Number(finalScore.toFixed(2)), decision, summary, analyst_notes:'Review source_links before bidding', last_verified_at:new Date().toISOString()}}];
